module crystal_oscillator (  
    input wire obf_clk,  
    input wire reset,  
    output reg out  
);  
    always @(posedge obf_clk or posedge reset) begin  
        if (reset) begin  
            out <= 0;  
        end else begin  
            out <= ~out;  
        end  
    end  
endmodule
